mapper.select:
SELECT COUNT(*)
FROM APPROVAL ap
WHERE ap.DRAFTER_ID = #{drafterId}

SELECT COUNT(*)
FROM APPROVAL ap
WHERE ap.DRAFTER_ID = #{drafterId}
  AND ap.APPROVAL_STATUS = #{status}

SELECT COUNT(DISTINCT ap.APPROVAL_ID)
FROM APPROVAL ap
WHERE ap.DRAFTER_ID != #{employeeId}
  AND ap.APPROVAL_STATUS != 'WITHDRAWN'
  AND ap.APPROVAL_ID IN (
      SELECT APPROVAL_ID FROM APPROVAL_REFERENCE WHERE DEPT_ID = #{deptId}
      UNION
      SELECT APPROVAL_ID FROM APPROVAL_REFERENCE WHERE EMPLOYEE_ID = #{employeeId}
      UNION
      SELECT APPROVAL_ID FROM APPROVAL_LINE WHERE APPROVER_ID = #{employeeId}
  )

mapper.update:
UPDATE APPROVAL
SET APPROVAL_STATUS = #{approvalStatus}
WHERE APPROVAL_ID = #{approvalId}
